const items = $input.all();
const results = [];

for (const item of items) {
  const file = item.json;
  const folderPath = file.parents?.[0]?.name || 'Unknown';
  const companyName = folderPath.replace(/[^a-zA-Z0-9\s]/g, '').trim();

  // Validate PE document types
  const supportedTypes = ['pdf', 'xlsx', 'docx', 'pptx'];
  const fileExtension = file.name.split('.').pop()?.toLowerCase();

  if (!supportedTypes.includes(fileExtension)) {
    continue;
  }

  // Categorize document type
  const fileName = file.name.toLowerCase();
  let documentType = 'other';

  if (fileName.includes('earnings') || fileName.includes('financial') || fileName.includes('10-k') || fileName.includes('10-q')) {
    documentType = 'financial_statements';
  } else if (fileName.includes('pitch') || fileName.includes('deck') || fileName.includes('presentation')) {
    documentType = 'pitch_deck';
  } else if (fileName.includes('market') || fileName.includes('research') || fileName.includes('analysis')) {
    documentType = 'market_research';
  } else if (fileName.includes('dd') || fileName.includes('due_diligence') || fileName.includes('memo')) {
    documentType = 'due_diligence';
  }

  results.push({
    json: {
      file_id: file.id,
      file_name: file.name,
      file_size: file.size,
      file_type: fileExtension,
      company_name: companyName,
      document_type: documentType,
      created_time: file.createdTime,
      modified_time: file.modifiedTime,
      download_url: file.webContentLink,
      folder_path: folderPath,
      processing_timestamp: new Date().toISOString(),
      analysis_id: `pe-${companyName.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}`,
      priority: documentType === 'financial_statements' ? 'high' : 'medium',
      ready_for_processing: true
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const content = item.json.text || '';

  // Extract key financial metrics using regex patterns
  const metrics = {
    revenue: extractMetric(content, /revenue[:\s]+\$?([0-9,\.]+)\s*(million|billion|m|b)?/gi),
    ebitda: extractMetric(content, /ebitda[:\s]+\$?([0-9,\.]+)\s*(million|billion|m|b)?/gi),
    net_income: extractMetric(content, /net\s+income[:\s]+\$?([0-9,\.]+)\s*(million|billion|m|b)?/gi),
    total_assets: extractMetric(content, /total\s+assets[:\s]+\$?([0-9,\.]+)\s*(million|billion|m|b)?/gi),
    debt: extractMetric(content, /(total\s+)?debt[:\s]+\$?([0-9,\.]+)\s*(million|billion|m|b)?/gi),
    employees: extractMetric(content, /employees?[:\s]+([0-9,]+)/gi)
  };

  function extractMetric(text, pattern) {
    const matches = text.match(pattern);
    if (matches && matches.length > 0) {
      const numbers = matches[0].match(/([0-9,\.]+)/g);
      return numbers ? parseFloat(numbers[0].replace(/,/g, '')) : null;
    }
    return null;
  }

  // Calculate basic ratios
  const ratios = {
    debt_to_assets: metrics.debt && metrics.total_assets ? metrics.debt / metrics.total_assets : null,
    ebitda_margin: metrics.ebitda && metrics.revenue ? metrics.ebitda / metrics.revenue : null,
    net_margin: metrics.net_income && metrics.revenue ? metrics.net_income / metrics.revenue : null
  };

  results.push({
    json: {
      ...item.json,
      extracted_metrics: metrics,
      calculated_ratios: ratios,
      extraction_timestamp: new Date().toISOString(),
      metrics_extracted: Object.values(metrics).some(v => v !== null),
      ready_for_analysis: true
    }
  });
}

return results;

